class Solution(object):
    def distinctDifferenceArray(self, nums):
        n = len(nums)
        result = []
        for i in range(n):
            prefix_distinct = len(set(nums[:i + 1]))
            suffix_distinct = len(set(nums[i + 1:]))
            result.append(prefix_distinct - suffix_distinct)
        return result
